#include <stdio.h>
#include <math.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        long long a, b;
        scanf("%lld %lld", &a, &b);
        long long count = 0;
        for (long long i = (long long)sqrt(a); i * i <= b; i++) {
            long long square = i * i;
            if (square >= a && square <= b) {
                int valid = 1;
                long long temp = square;
                while (temp > 0) {
                    int digit = temp % 10;
                    if (digit != 0 && digit != 1 && digit != 4 && digit != 9) {
                        valid = 0;
                        break;
                    }
                    temp /= 10;
                }
                if (valid) count++;
            }
        }
        printf("%lld\n", count);
    }
    return 0;
}

