import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            long a = sc.nextLong();
            long b = sc.nextLong();
            long count = 0;
            for (long i = (long)Math.sqrt(a); i * i <= b; i++) {
                long square = i * i;
                if (square >= a && square <= b) {
                    int valid = 1;
                    long temp = square;
                    while (temp > 0) {
                        int digit = (int) (temp % 10);
                        if (digit != 0 && digit != 1 && digit != 4 && digit != 9) {
                            valid = 0;
                            break;
                        }
                        temp /= 10;
                    }
                    if (valid) count++;
                }
            }
            System.out.println(count);
        }
    }
}

