const lines = require('fs').readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => lines[idx++];
const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const [a, b] = readline().split(' ').map(Number);
    let count = 0;
    for (let j = Math.ceil(Math.sqrt(a)); j * j <= b; j++) {
        const square = j * j;
        if (square >= a && square <= b) {
            let valid = true;
            let temp = square;
            while (temp > 0) {
                const digit = temp % 10;
                if (digit !== 0 && digit !== 1 && digit !== 4 && digit !== 9) {
                    valid = false;
                    break;
                }
                temp = Math.floor(temp / 10);
            }
            if (valid) count++;
        }
    }
    console.log(count);
}

